            "def bb_detector(H, y, sigma2, constellation):\n"
            "    Nt = H.shape[1]\n"
            "    x = np.zeros(Nt, dtype=complex)\n"
            "    with slot('bb.gradient', inputs=(H, y, sigma2, x), outputs=('g_old',)):\n"
            "        _bb_gradient__r = y - H @ x\n"
            "        g_old = H.conj().T @ _bb_gradient__r\n"
            "    x = x + 0.01 * g_old\n"
            "    i = 0\n"
            "    while i < 30:\n"
            "        with slot('bb.gradient_2', inputs=(H, y, sigma2, x), outputs=('g',)):\n"
            "            _bb_gradient_2__r = y - H @ x\n"
            "            g = H.conj().T @ _bb_gradient_2__r\n"
            "        dg = g - g_old\n"
            "        dx = 0.01 * g_old\n"
            "        dg_norm = float(np.real(np.conj(dg) @ dg))\n"
            "        alpha = float(np.real(np.conj(dx) @ dg)) / max(dg_norm, 1e-30)\n"
            "        alpha = max(0.0001, min(abs(alpha), 0.1))\n"
            "        x = x + alpha * g\n"
            "        g_old = g.copy()\n"
