            "            _penalty_project__i = 0\n"
            "            while _penalty_project__i < len(x):\n"
            "                _penalty_project__re = float(np.real(x[_penalty_project__i]))\n"
            "                _penalty_project__im = float(np.imag(x[_penalty_project__i]))\n"
            "                _penalty_project__re = max(-_penalty_project__bound, min(_penalty_project__bound, _penalty_project__re))\n"
