            "            _layer_peeling_weight__Nt = H_rem.shape[1]\n"
            "            _layer_peeling_weight__G = H_rem.conj().T @ H_rem + sigma2 * np.eye(_layer_peeling_weight__Nt)\n"
            "            W = np.linalg.inv(_layer_peeling_weight__G) @ H_rem.conj().T\n"
            "        x_soft = W @ y_rem\n"
            "        best_j = -1\n"
