            "                _dp_detect_score_2__r = y - H @ x\n"
            "                best_c = float(np.real(np.conj(_dp_detect_score_2__r) @ _dp_detect_score_2__r))\n"
            "            ci = 0\n"
            "            while ci < M:\n"
