            "        while j < Nt:\n"
            "            s = 0.0 + 0j\n"
            "            k = 0\n"
            "            while k < Nt:\n"
            "                if k != j:\n"
            "                    s = s + G[j, k] * x[k]\n"
            "                k = k + 1\n"
            "            x[j] = (rhs[j] - s) / G[j, j]\n"
            "            j = j + 1\n"
            "        it = it + 1\n"
