            "    i = 0\n"
            "    while i < 30:\n"
            "        with slot('gpa.gradient', inputs=(H, y, sigma2, x), outputs=('g',)):\n"
            "            _gpa_gradient__r = y - H @ x\n"
            "            g = H.conj().T @ _gpa_gradient__r\n"
            "        x_grad = x + 0.01 * g\n"
            "        with slot('gpa.project', inputs=(x_grad, constellation), outputs=('x_proj',)):\n"
            "            _gpa_project__Nt = len(x_grad)\n"
            "            _gpa_project__x_proj = np.zeros(_gpa_project__Nt, dtype=complex)\n"
            "            _gpa_project__i = 0\n"
