            "                _gpa_project__x_proj[_gpa_project__i] = constellation[np.argmin(_gpa_project__dists)]\n"
            "                _gpa_project__i = _gpa_project__i + 1\n"
            "            x_proj = _gpa_project__x_proj\n"
            "        with slot('gpa.damping', inputs=(x, x_proj), outputs=('x',)):\n"
            "            _gpa_damping__alpha = 0.5\n"
